const items = $input.all();

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'title') return (prop.title || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'url') return prop.url || '';
  if (prop.type === 'number') return prop.number ?? '';
  if (prop.type === 'checkbox') return prop.checkbox || false;
  return '';
}

const defaults = {
  siteKey: 'leyicasedemo',
  brandName: '數位服務處',
  brandShortName: '數位服務處',
  adminName: '市民服務平台',
  systemMode: 'achievement',
  primaryColor: '#E87F24',
  accentColor: '#FFC81E',
  logoUrl: 'leyi/assets/brand/logo.png',
  heroTitleLine1: '數位時代的',
  heroTitleLine2: '市民服務新標準',
  heroSubtitle: '透過數位化陳情平台，每一件市民的問題都將被看見、被追蹤、被解決。',
  lineUrl: 'https://lin.ee/Q9cWSP5',
  webhookBase: 'https://drwu.zeabur.app',
  webhookMode: 'webhook',
  webhookPrefix: 'leyicasedemo',
  inspectionsCount: 156,
  interpellationsCount: 83,
  proposalsCount: 29,
  isActive: true
};

if (!items.length) {
  return [{ json: { success: true, source: 'fallback', settings: defaults } }];
}

const props = items[0].json.properties || {};
const rawTitle = getText(props['首頁標題']);
const titleParts = rawTitle.split(/\r?\n|\|/).map(v => v.trim()).filter(Boolean);

const settings = {
  siteKey: getText(props['網站代碼']) || defaults.siteKey,
  brandName: getText(props['品牌名稱']) || defaults.brandName,
  brandShortName: getText(props['品牌簡稱']) || getText(props['品牌名稱']) || defaults.brandShortName,
  adminName: getText(props['後台名稱']) || defaults.adminName,
  systemMode: getText(props['系統模式']) || defaults.systemMode,
  primaryColor: getText(props['主色']) || defaults.primaryColor,
  accentColor: getText(props['輔助色']) || defaults.accentColor,
  logoUrl: getText(props['Logo圖片']) || defaults.logoUrl,
  heroTitleLine1: titleParts[0] || defaults.heroTitleLine1,
  heroTitleLine2: titleParts[1] || defaults.heroTitleLine2,
  heroSubtitle: getText(props['首頁副標']) || defaults.heroSubtitle,
  lineUrl: getText(props['LINE連結']) || defaults.lineUrl,
  webhookBase: getText(props['WebhookBase']) || defaults.webhookBase,
  webhookMode: 'webhook',
  webhookPrefix: getText(props['WebhookPrefix']) || defaults.webhookPrefix,
  inspectionsCount: Number(getText(props['地方會勘數量']) || defaults.inspectionsCount),
  interpellationsCount: Number(getText(props['國會質詢數量']) || defaults.interpellationsCount),
  proposalsCount: Number(getText(props['國會提案數量']) || defaults.proposalsCount),
  isActive: getText(props['是否啟用']) !== false
};

return [{ json: { success: true, source: 'notion', settings } }];
